<template>
  <div class="tool-content" style="font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Text', 'PingFang SC', 'Microsoft YaHei', sans-serif">
    <div
      style="
        background: rgba(102, 126, 234, 0.1);
        border-left: 3px solid #667eea;
        padding: 12px 15px;
        border-radius: 8px;
        margin-bottom: 18px;
      "
    >
      <p style="margin: 0; color: #c7d2fe; font-size: 13px; display: flex; align-items: center; gap: 8px">
        <i class="fa-solid fa-info-circle" style="color: #667eea"></i>
        选择一个世界书，查看其中所有条目的详细信息，支持搜索和筛选。
      </p>
    </div>

    <!-- 选择世界书 -->
    <div style="margin-bottom: 18px">
      <label style="display: block; margin-bottom: 8px; color: #e0e0e0; font-size: 14px; font-weight: 500">选择世界书：</label>
      <select
        v-model="selectedViewerWorldbook"
        :style="inputStyle"
        @change="loadWorldbookEntries"
      >
        <option value="">请选择世界书</option>
        <option v-for="wb in availableWorldbooks" :key="wb" :value="wb">{{ wb }}</option>
      </select>
    </div>

    <!-- 搜索条目 -->
    <div v-if="selectedViewerWorldbook" style="margin-bottom: 18px">
      <label style="display: block; margin-bottom: 8px; color: #e0e0e0; font-size: 14px; font-weight: 500">搜索条目：</label>
      <input v-model="viewerSearchQuery" type="text" placeholder="搜索条目名称、关键字或内容..." :style="inputStyle" />
    </div>

    <!-- 排序 -->
    <div v-if="selectedViewerWorldbook && worldbookEntries.length > 0" style="display: flex; gap: 10px; margin-bottom: 15px">
      <button :style="pillStyle(viewerSortBy === 'original')" @click="viewerSortBy = 'original'">原始顺序</button>
      <button :style="pillStyle(viewerSortBy === 'enabled')" @click="viewerSortBy = 'enabled'">
        <i class="fa-solid fa-check" style="margin-right: 4px"></i>仅启用
      </button>
      <button :style="pillStyle(viewerSortBy === 'disabled')" @click="viewerSortBy = 'disabled'">
        <i class="fa-solid fa-xmark" style="margin-right: 4px"></i>仅禁用
      </button>
    </div>

    <!-- 统计 -->
    <div v-if="selectedViewerWorldbook" style="margin-bottom: 15px; color: #888; font-size: 12px">
      <span v-if="filteredWorldbookEntries.length > 0">共找到 {{ filteredWorldbookEntries.length }} 个条目</span>
      <span v-else style="color: #ff6b6b">未找到条目</span>
    </div>

    <!-- 条目列表 -->
    <div v-if="filteredWorldbookEntries.length > 0" style="display: flex; flex-direction: column; gap: 12px">
      <div
        v-for="(entry, index) in filteredWorldbookEntries"
        :key="index"
        style="background: rgba(255,255,255,0.05); border: 0.5px solid rgba(255,255,255,0.08); border-radius: 14px; padding: 14px"
      >
        <div style="display: flex; justify-content: space-between; align-items: flex-start; cursor: pointer; user-select: none" @click="toggleEntryExpanded(index)">
          <div style="flex: 1; line-height: 1.6">
            <div style="display: flex; align-items: center; gap: 6px; margin-bottom: 8px">
              <span
                :style="{
                  width: '9px',
                  height: '9px',
                  borderRadius: '50%',
                  flex: '0 0 auto',
                  background:
                    entry.strategy?.type === 'constant'
                      ? '#0a84ff'
                      : entry.strategy?.type === 'selective'
                        ? '#30d158'
                        : 'rgba(235,235,245,0.4)',
                }"
              ></span>
              <span style="color: #f5f5f7; font-weight: 600; font-size: 14px">{{ entry.name || '(无名称)' }}</span>
            </div>
            <div style="padding-left: 20px; margin-bottom: 6px; font-size: 12px; color: #ccc">
              <span v-if="entry.strategy?.keys && entry.strategy.keys.length > 0">
                关键词: {{ entry.strategy.keys.map((k: any) => (typeof k === 'string' ? k : String(k))).join(', ') }}
              </span>
              <span v-else>关键词: (无)</span>
            </div>
            <div style="padding-left: 20px; font-size: 12px; color: #999; font-style: italic">
              {{ entry.content ? (entry.content.length > 50 ? entry.content.substring(0, 50) + '...' : entry.content) : '(无内容)' }}
            </div>
          </div>
          <i :class="isEntryExpanded(index) ? 'fa-solid fa-chevron-up' : 'fa-solid fa-chevron-down'" style="color: #888; font-size: 12px; margin-top: 2px"></i>
        </div>

        <div v-if="isEntryExpanded(index)" style="margin-top: 15px; padding-top: 15px; border-top: 0.5px solid rgba(255,255,255,0.08)">
          <div style="margin-bottom: 12px">
            <span style="color: #888; font-size: 12px; font-weight: 600; display: block; margin-bottom: 6px"><i class="fa-solid fa-file-lines" style="margin-right: 5px"></i>条目内容：</span>
            <div style="padding: 12px; background: rgba(0,0,0,0.25); border-radius: 8px; color: #ccc; font-size: 12px; line-height: 1.6; max-height: 200px; overflow-y: auto; white-space: pre-wrap">
              {{ entry.content || '(无内容)' }}
            </div>
          </div>
          <div style="display: flex; gap: 10px; margin-top: 12px">
            <button :style="actionBtn('#0a84ff')" @click="editWorldbookEntry(entry)"><i class="fa-solid fa-edit"></i> 编辑</button>
            <button :style="actionBtn('rgba(255,69,58,0.18)', '#ff6961')" @click="deleteEntry(entry)"><i class="fa-solid fa-trash"></i> 删除</button>
          </div>
        </div>
      </div>
    </div>

    <!-- 编辑对话框 -->
    <div
      v-if="showEditDialog"
      style="position: fixed; inset: 0; background: rgba(0,0,0,0.7); display: flex; align-items: center; justify-content: center; z-index: 10000; backdrop-filter: blur(8px)"
      @click.self="showEditDialog = false"
    >
      <div style="background: #1c1c1e; border: 0.5px solid rgba(255,255,255,0.12); border-radius: 20px; padding: 24px; max-width: 700px; width: 92%; max-height: 85vh; overflow-y: auto; box-shadow: 0 30px 90px rgba(0,0,0,0.6); color: #f5f5f7">
        <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px">
          <h3 style="margin: 0; color: #f5f5f7; font-size: 17px; font-weight: 700"><i class="fa-solid fa-edit" style="margin-right: 8px; color: #0a84ff"></i>编辑世界书条目</h3>
          <button style="background: rgba(255,255,255,0.1); border: none; border-radius: 50%; width: 30px; height: 30px; color: rgba(235,235,245,0.8); font-size: 15px; cursor: pointer" @click="showEditDialog = false"><i class="fa-solid fa-times"></i></button>
        </div>
        <div style="display: flex; flex-direction: column; gap: 14px">
          <div>
            <label :style="labelStyle">条目名称：</label>
            <input v-model="editingEntry.name" type="text" :style="inputStyle" />
          </div>
          <label style="color: #e0e0e0; font-size: 14px; display: flex; align-items: center; gap: 10px; cursor: pointer">
            <input v-model="editingEntry.enabled" type="checkbox" style="width: 17px; height: 17px; accent-color: #30d158" /> 启用此条目
          </label>
          <div>
            <label :style="labelStyle">主要关键字（逗号分隔）：</label>
            <input
              :value="(editingEntry.strategy?.keys || []).map((k: any) => (typeof k === 'string' ? k : String(k))).join(',')"
              type="text"
              placeholder="如：艾莉娅,Aria,精灵"
              :style="inputStyle"
              @input="onKeysInput"
            />
          </div>
          <div>
            <label :style="labelStyle">触发类型：</label>
            <select :value="editingEntry.strategy?.type || 'selective'" :style="inputStyle" @change="onTypeChange">
              <option value="selective">绿灯 (可选项)</option>
              <option value="constant">蓝灯 (常量)</option>
            </select>
          </div>
          <div>
            <label :style="labelStyle">条目内容：</label>
            <textarea v-model="editingEntry.content" :style="textareaStyle"></textarea>
          </div>
        </div>
        <div style="display: flex; gap: 10px; margin-top: 20px; justify-content: flex-end">
          <button style="padding: 9px 18px; background: rgba(255,255,255,0.1); border: none; border-radius: 11px; color: #f5f5f7; font-size: 14px; cursor: pointer" @click="showEditDialog = false">取消</button>
          <button style="padding: 9px 18px; background: #0a84ff; border: none; border-radius: 11px; color: #fff; font-size: 14px; font-weight: 600; cursor: pointer" @click="saveEditedEntry"><i class="fa-solid fa-save" style="margin-right: 6px"></i>保存</button>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed, onMounted, ref } from 'vue';
import { translateError } from '../../utils/error-handler';
import { useWorldbook } from './useToolsCommon';

const { availableWorldbooks, loadAvailableWorldbooks } = useWorldbook();

const selectedViewerWorldbook = ref('');
const worldbookEntries = ref<WorldbookEntry[]>([]);
const viewerSearchQuery = ref('');
const viewerSortBy = ref<'original' | 'enabled' | 'disabled'>('original');
const entryExpandedState = ref(new Map<number, boolean>());

const showEditDialog = ref(false);
const editingEntry = ref<Partial<WorldbookEntry>>({});
const editingEntryUid = ref<number | null>(null);

const inputStyle =
  'width: 100%; box-sizing: border-box; padding: 11px 13px; background: rgba(255,255,255,0.06); border: 0.5px solid rgba(255,255,255,0.12); border-radius: 12px; color: #f5f5f7; font-size: 14px; cursor: pointer; font-family: inherit;';
const textareaStyle =
  'width: 100%; box-sizing: border-box; min-height: 200px; padding: 11px 13px; background: rgba(255,255,255,0.06); border: 0.5px solid rgba(255,255,255,0.12); border-radius: 12px; color: #f5f5f7; font-size: 14px; resize: vertical; font-family: inherit; line-height: 1.55;';
const labelStyle = 'display: block; margin-bottom: 8px; color: #e0e0e0; font-size: 14px; font-weight: 500;';

function pillStyle(active: boolean): string {
  return `padding: 8px 16px; background: ${active ? 'rgba(10,132,255,0.2)' : 'rgba(255,255,255,0.06)'}; border: 0.5px solid ${active ? '#0a84ff' : 'rgba(255,255,255,0.12)'}; border-radius: 999px; color: ${active ? '#4ea1ff' : '#e0e0e0'}; font-size: 12px; cursor: pointer;`;
}
function actionBtn(bg: string, color = '#fff'): string {
  return `padding: 8px 16px; background: ${bg}; border: none; border-radius: 999px; color: ${color}; font-size: 12px; cursor: pointer;`;
}

const loadWorldbookEntries = async () => {
  if (!selectedViewerWorldbook.value) {
    worldbookEntries.value = [];
    return;
  }
  try {
    const TH = (window as any).TavernHelper;
    if (typeof TH?.getWorldbook !== 'function') {
      window.toastr.error('世界书功能需要酒馆助手支持');
      worldbookEntries.value = [];
      return;
    }
    const worldbook = await TH.getWorldbook(selectedViewerWorldbook.value);
    if (worldbook && Array.isArray(worldbook) && worldbook.length > 0) {
      worldbookEntries.value = worldbook;
      window.toastr.success(`已加载 ${worldbookEntries.value.length} 个条目`);
    } else {
      worldbookEntries.value = [];
      window.toastr.info('该世界书没有条目');
    }
  } catch (error) {
    console.error('❌ 加载世界书条目失败:', error);
    window.toastr.error(translateError(error, '加载'));
    worldbookEntries.value = [];
  }
};

const filteredWorldbookEntries = computed(() => {
  let entries = [...worldbookEntries.value];
  if (viewerSearchQuery.value.trim()) {
    const query = viewerSearchQuery.value.toLowerCase();
    entries = entries.filter(entry => {
      const nameMatch = entry.name?.toLowerCase().includes(query);
      const contentMatch = entry.content?.toLowerCase().includes(query);
      const keysMatch = entry.strategy?.keys?.some(key =>
        (typeof key === 'string' ? key : String(key)).toLowerCase().includes(query),
      );
      return nameMatch || contentMatch || keysMatch;
    });
  }
  if (viewerSortBy.value === 'enabled') entries = entries.filter(e => e.enabled);
  else if (viewerSortBy.value === 'disabled') entries = entries.filter(e => !e.enabled);
  return entries;
});

const toggleEntryExpanded = (index: number) => {
  entryExpandedState.value.set(index, !(entryExpandedState.value.get(index) || false));
};
const isEntryExpanded = (index: number) => entryExpandedState.value.get(index) || false;

const onKeysInput = (e: any) => {
  const keys = e.target.value.split(',').filter((k: string) => k.trim()).map((k: string) => k.trim());
  editingEntry.value.strategy = {
    ...editingEntry.value.strategy,
    keys,
    keys_secondary: editingEntry.value.strategy?.keys_secondary || { logic: 'and_any', keys: [] },
    scan_depth: editingEntry.value.strategy?.scan_depth || 'same_as_global',
    type: editingEntry.value.strategy?.type || 'selective',
  } as any;
};
const onTypeChange = (e: any) => {
  editingEntry.value.strategy = {
    ...editingEntry.value.strategy,
    type: e.target.value,
    keys: editingEntry.value.strategy?.keys || [],
    keys_secondary: editingEntry.value.strategy?.keys_secondary || { logic: 'and_any', keys: [] },
    scan_depth: editingEntry.value.strategy?.scan_depth || 'same_as_global',
  } as any;
};

const editWorldbookEntry = (entry: WorldbookEntry) => {
  try {
    editingEntry.value = {
      uid: entry.uid,
      name: entry.name || '',
      enabled: entry.enabled ?? true,
      content: entry.content || '',
      strategy: {
        type: entry.strategy?.type || 'selective',
        keys: [...(entry.strategy?.keys || [])],
        keys_secondary: {
          logic: entry.strategy?.keys_secondary?.logic || 'and_any',
          keys: [...(entry.strategy?.keys_secondary?.keys || [])],
        },
        scan_depth: entry.strategy?.scan_depth || 'same_as_global',
      },
      position: entry.position
        ? { ...entry.position }
        : { type: 'before_character_definition', role: 'system', depth: 0, order: 0 },
      probability: entry.probability ?? 100,
      recursion: entry.recursion
        ? { ...entry.recursion }
        : { prevent_incoming: false, prevent_outgoing: false, delay_until: null },
      effect: entry.effect ? { ...entry.effect } : { sticky: null, cooldown: null, delay: null },
    };
    editingEntryUid.value = entry.uid;
    showEditDialog.value = true;
  } catch (error) {
    console.error('打开编辑界面失败:', error);
    window.toastr.error(translateError(error, '打开编辑界面'));
  }
};

const saveEditedEntry = async () => {
  if (!editingEntry.value.name?.trim()) {
    window.toastr.warning('条目名称不能为空');
    return;
  }
  if (editingEntryUid.value == null) {
    window.toastr.error('条目ID不存在');
    return;
  }
  try {
    const TH = (window as any).TavernHelper;
    if (!TH) throw new Error('TavernHelper 不可用，请确保在 SillyTavern 环境中运行');
    const updatedWorldbook = await TH.updateWorldbookWith(selectedViewerWorldbook.value, (worldbook: any) => {
      const idx = worldbook.findIndex((e: any) => e.uid === editingEntryUid.value);
      if (idx !== -1) {
        worldbook[idx] = { ...worldbook[idx], ...editingEntry.value, uid: editingEntryUid.value };
      }
      return worldbook;
    });
    worldbookEntries.value = updatedWorldbook;
    showEditDialog.value = false;
    editingEntry.value = {};
    editingEntryUid.value = null;
    window.toastr.success('条目已保存');
  } catch (error) {
    console.error('保存条目失败:', error);
    window.toastr.error(translateError(error, '保存'));
  }
};

const deleteEntry = async (entry: WorldbookEntry) => {
  if (!confirm(`确定要删除条目 "${entry.name}" 吗？`)) return;
  try {
    const { worldbook } = await deleteWorldbookEntries(selectedViewerWorldbook.value, (e: any) => e.uid === entry.uid);
    worldbookEntries.value = worldbook;
    window.toastr.success(`已删除条目 "${entry.name}"`);
  } catch (error) {
    console.error('删除条目失败:', error);
    window.toastr.error(translateError(error, '删除'));
  }
};

onMounted(loadAvailableWorldbooks);
</script>
